if post1_self_.valid()
        && post1_self_@.len() == pre_self_@.len() + 1
        && 0 <= r1 < post1_self_@.len()
        && post1_self_@ == pre_self_@.insert(r1 as int, k)
        && post2_self_.valid()
        && post2_self_@.len() == pre_self_@.len() + 1
        && 0 <= r2 < post2_self_@.len()
        && post2_self_@ == pre_self_@.insert(r2 as int, k)
    {
        let s: Seq<K> = pre_self_@;
        let r1_i: int = r1 as int;
        let r2_i: int = r2 as int;

        pre_self_@.insert_ensures(r1_i, k);
        pre_self_@.insert_ensures(r2_i, k);
        K::cmp_properties();

        if r1_i < r2_i {
            assert(r1_i < s.len());
            assert(post1_self_@[r1_i] == k);
            assert(post1_self_@[r1_i + 1] == s[r1_i]);
            assert(0 <= r1_i && r1_i + 1 < post1_self_@.len());
            assert(post1_self_@[r1_i].cmp_spec(post1_self_@[r1_i + 1]).lt());

            assert(post2_self_@[r1_i] == s[r1_i]);
            assert(post2_self_@[r2_i] == k);
            assert(0 <= r1_i && r1_i < r2_i && r2_i < post2_self_@.len());
            assert(post2_self_@[r1_i].cmp_spec(post2_self_@[r2_i]).lt());

            assert(k.cmp_spec(s[r1_i]).lt());
            assert(s[r1_i].cmp_spec(k).lt());
            assert(false);
        } else if r2_i < r1_i {
            assert(r2_i < s.len());
            assert(post2_self_@[r2_i] == k);
            assert(post2_self_@[r2_i + 1] == s[r2_i]);
            assert(0 <= r2_i && r2_i + 1 < post2_self_@.len());
            assert(post2_self_@[r2_i].cmp_spec(post2_self_@[r2_i + 1]).lt());

            assert(post1_self_@[r2_i] == s[r2_i]);
            assert(post1_self_@[r1_i] == k);
            assert(0 <= r2_i && r2_i < r1_i && r1_i < post1_self_@.len());
            assert(post1_self_@[r2_i].cmp_spec(post1_self_@[r1_i]).lt());

            assert(k.cmp_spec(s[r2_i]).lt());
            assert(s[r2_i].cmp_spec(k).lt());
            assert(false);
        }

        assert(r1_i == r2_i);
        assert(r1 == r2);
        assert(post1_self_@ =~= post2_self_@);
        assert(post1_self_@ == post2_self_@);
        assert(post1_self_.v =~= post2_self_.v);
        assert(post1_self_ == post2_self_);
        assert(det_insert_equal(r1, r2, post1_self_, post2_self_));
    }
